@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor black
skinparam classFontColor black
skinparam classStereotypeFontColor black
skinparam classStereotypeBackgroundColor #A8D5BA
skinparam classStereotypeBorderColor black
skinparam classStereotypeFontStyle bold

class "Pizza" as Pizza {
    void prepare();
    void back();
    void cut();
    void box();
}

class "PepperPizza" as PepperPizza
class "GreakPizza" as GreakPizza
class "CheesePizza" as CheesePizza

class "SimpleFactory" as SimpleFactory {
    Pizza createPizza();
}

class "OrderPizza" as OrderPizza
class "OrderPizza2" as OrderPizza2
class "OrderPizza3" as OrderPizza3

Pizza <|-- PepperPizza
Pizza <|-- GreakPizza
Pizza <|-- CheesePizza

SimpleFactory --> PepperPizza
SimpleFactory --> GreakPizza
SimpleFactory --> CheesePizza

OrderPizza --o SimpleFactory
OrderPizza2 --o SimpleFactory
OrderPizza3 --o SimpleFactory

@enduml
